// Final form of `mean()` from this chapter: accepts a slice (`&[f64]`),
// which works for both `Vec&lt;f64&gt;` and arrays without moving them.
fn mean(x: &[f64]) -&gt; f64 {
    let mut total = 0.0;
    for xi in x {
        total += xi;
    }
    total / x.len() as f64
}

