Solution


View solution

fn mean(x: &[f64]) -&gt; f64 {
    let total: f64 = x.iter().sum();
    total / x.len() as f64
}

// Exercise 1: variance via `.map()` + `.sum()`
fn variance(x: &[f64]) -&gt; f64 {
    let n = x.len() as f64;
    let avg = mean(x);
    let sq_diffs: f64 = x.iter().map(|xi| (xi - avg).powi(2)).sum();
